import React, { useState, useEffect, useCallback, useRef } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useSelector } from 'react-redux'
import { useTheme } from '../context/ThemeContext'
import api from '../services/axios'
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  KeyboardSensor,
  useSensor,
  useSensors,
  closestCenter,
  pointerWithin,
  rectIntersection,
  getFirstCollision,
  useDroppable,
} from '@dnd-kit/core'
import {
  SortableContext,
  verticalListSortingStrategy,
  useSortable,
  arrayMove,
  sortableKeyboardCoordinates,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import { io } from 'socket.io-client'
import ConfirmModal from '../components/ConfirmModal'
import Toast from '../components/Toast'

const PRIORITY_CONFIG = {
  urgent: {
    icon: 'flag',
    color: '#ef4444',
    label: 'Urgent'
  },
  high: {
    icon: 'keyboard_arrow_up',
    color: '#f97316',
    label: 'High'
  },
  medium: {
    icon: 'remove',
    color: '#eab308',
    label: 'Medium'
  },
  low: {
    icon: 'keyboard_arrow_down',
    color: '#94a3b8',
    label: 'Low'
  },
}

const COLUMN_COLORS = {
  'To Do': '#94a3b8',
  'In Progress': '#6366f1',
  'Review': '#f59e0b',
  'Done': '#10b981',
}

const LABEL_COLORS = [
  { bg: 'rgba(59,130,246,0.15)', text: '#60a5fa',
    bgLight: '#dbeafe', textLight: '#1d4ed8' },
  { bg: 'rgba(16,185,129,0.15)', text: '#34d399',
    bgLight: '#d1fae5', textLight: '#065f46' },
  { bg: 'rgba(139,92,246,0.15)', text: '#a78bfa',
    bgLight: '#ede9fe', textLight: '#5b21b6' },
  { bg: 'rgba(239,68,68,0.15)', text: '#f87171',
    bgLight: '#fee2e2', textLight: '#991b1b' },
  { bg: 'rgba(245,158,11,0.15)', text: '#fbbf24',
    bgLight: '#fef3c7', textLight: '#92400e' },
]

const getLabelColor = (label, isDark) => {
  const idx = label.charCodeAt(0) % LABEL_COLORS.length
  const c = LABEL_COLORS[idx]
  return isDark
    ? { bg: c.bg, text: c.text }
    : { bg: c.bgLight, text: c.textLight }
}

const getColumnColor = (name) =>
  COLUMN_COLORS[name] || '#6366f1'


const timeAgo = (date) => {
  const diff = Date.now() - new Date(date)
  const mins = Math.floor(diff / 60000)
  if (mins < 1) return 'Just now'
  if (mins < 60) return `${mins}m ago`
  const hrs = Math.floor(mins / 60)
  if (hrs < 24) return `${hrs}h ago`
  return new Date(date).toLocaleDateString('en-US',
    { month: 'short', day: 'numeric' })
}

function TaskCard({ task, isDark, onClick, onDelete }) {
  const [showMenu, setShowMenu] = useState(false)
  const [showCardDeleteConfirm, setShowCardDeleteConfirm] = useState(false)
  const menuRef = useRef(null)

  useEffect(() => {
    const handleClick = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) {
        setShowMenu(false)
      }
    }
    if (showMenu) document.addEventListener('mousedown', handleClick)
    return () => document.removeEventListener('mousedown', handleClick)
  }, [showMenu])
  const {
    attributes, listeners, setNodeRef,
    transform, transition, isDragging: isSortableDragging,
  } = useSortable({ id: task._id })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isSortableDragging ? 0.4 : 1,
  }

  const priority = PRIORITY_CONFIG[task.priority] ||
                   PRIORITY_CONFIG.medium
  const isOverdue = task.dueDate &&
    new Date(task.dueDate) < new Date() &&
    task.status !== 'done'

  return (
    <div
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...listeners}
      onClick={(e) => {
        if (!isSortableDragging) onClick(task)
      }}
      className={`group p-3 rounded-lg border cursor-grab
        active:cursor-grabbing select-none
        transition-all duration-150
        ${isDark
          ? 'bg-[#1c1c1c] border-[rgba(255,255,255,0.08)] hover:border-[rgba(255,255,255,0.18)]'
          : 'bg-white border-slate-200 shadow-sm hover:shadow-md hover:border-slate-300'
        }`}
    >
      <div className="flex items-start justify-between mb-2">
        <span
          className="material-symbols-outlined text-[16px]"
          style={{ color: priority.color }}
        >
          {priority.icon}
        </span>
        <div className="relative">
          <button
            onClick={(e) => {
              e.stopPropagation()
              setShowMenu(p => !p)
            }}
            className={`opacity-0 group-hover:opacity-100
              rounded p-0.5 transition-all
              ${isDark
                ? 'text-slate-600 hover:text-slate-300 hover:bg-[rgba(255,255,255,0.06)]'
                : 'text-slate-300 hover:text-slate-500 hover:bg-slate-100'
              } ${showMenu ? 'opacity-100 bg-white/5' : ''}`}
          >
            <span className="material-symbols-outlined text-[16px]">
              more_horiz
            </span>
          </button>

          {showMenu && (
            <div 
              ref={menuRef}
              className={`absolute right-0 top-7 w-32
              rounded-xl shadow-xl z-20 overflow-hidden
              ${isDark
                ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
                : 'bg-white border border-slate-200'
              }`}
            >
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setShowMenu(false)
                  onClick(task)
                }}
                className={`w-full flex items-center gap-2
                           px-3 py-2 text-xs text-left
                           ${isDark ? 'hover:bg-white/5 text-slate-300' : 'hover:bg-slate-50 text-slate-700'}`}
              >
                <span className="material-symbols-outlined text-[14px]">open_in_new</span>
                Open
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setShowMenu(false)
                  setShowCardDeleteConfirm(true)
                }}
                className="w-full flex items-center gap-2
                           px-3 py-2 text-xs text-red-500
                           hover:bg-red-500/10 transition-colors
                           cursor-pointer"
              >
                <span className="material-symbols-outlined text-[14px]">delete</span>
                Delete
              </button>
            </div>
          )}
        </div>
      </div>

      {showCardDeleteConfirm && (
        <div className="fixed inset-0 bg-black/60
          backdrop-blur-sm z-[200]
          flex items-center justify-center px-4"
          onClick={e => e.stopPropagation()}>
          <div className={`w-full max-w-sm rounded-2xl
            shadow-2xl p-6
            ${isDark
              ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
              : 'bg-white border border-slate-200'
            }`}>
            <div className="size-12 rounded-full
              bg-red-500/10 flex items-center
              justify-center mb-4">
              <span className="material-symbols-outlined
                               text-[24px] text-red-500">
                delete
              </span>
            </div>
            <h3 className={`text-base font-semibold mb-2
              ${isDark ? 'text-white' : 'text-slate-900'}`}>
              Delete Task
            </h3>
            <p className={`text-sm mb-6
              ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
              <span className="font-semibold">
                {task.title}
              </span>
              {' '}will be permanently deleted.
            </p>
            <div className="flex gap-3">
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setShowCardDeleteConfirm(false)
                }}
                className={`flex-1 py-2.5 rounded-xl
                  text-sm font-semibold border cursor-pointer
                  transition-colors
                  ${isDark
                    ? 'border-[rgba(255,255,255,0.08)] text-slate-400 hover:bg-[rgba(255,255,255,0.06)]'
                    : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                  }`}>
                Cancel
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setShowCardDeleteConfirm(false)
                  onDelete(task._id)
                }}
                className="flex-1 py-2.5 rounded-xl
                  text-sm font-semibold text-white
                  bg-red-600 hover:bg-red-700
                  cursor-pointer transition-colors">
                Delete Task
              </button>
            </div>
          </div>
        </div>
      )}

      <p className={`text-sm font-medium leading-snug
        mb-2 line-clamp-2
        ${task.status === 'done'
          ? 'line-through opacity-60'
          : isDark ? 'text-slate-100' : 'text-slate-900'
        }`}>
        {task.title}
      </p>

      {task.labels?.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-2">
          {task.labels.map((label, i) => {
            const c = getLabelColor(label, isDark)
            return (
              <span
                key={i}
                style={{
                  backgroundColor: c.bg,
                  color: c.text
                }}
                className="text-[9px] font-bold uppercase
                           px-1.5 py-0.5 rounded-sm
                           tracking-wider"
              >
                {label}
              </span>
            )
          })}
        </div>
      )}

      <div className="flex items-center justify-between mt-2">
        <div className="flex items-center gap-2">
          {task.dueDate && (
            <span className={`flex items-center gap-0.5
              text-[10px]
              ${isOverdue
                ? 'text-red-500'
                : isDark ? 'text-slate-600' : 'text-slate-400'
              }`}>
              <span className="material-symbols-outlined
                               text-[12px]">
                schedule
              </span>
              {new Date(task.dueDate)
                .toLocaleDateString('en-US',
                  { month: 'short', day: 'numeric' })}
            </span>
          )}
          {task.commentCount > 0 && (
            <span className={`flex items-center gap-0.5
              text-[10px]
              ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
              <span className="material-symbols-outlined
                               text-[12px]">
                chat_bubble
              </span>
              {task.commentCount}
            </span>
          )}
        </div>

        <div className="flex">
          {task.assignees?.length > 0
            ? task.assignees.slice(0, 2).map((a, i) => (
                <div
                  key={a._id || i}
                  className="size-5 rounded-full border
                             overflow-hidden flex items-center
                             justify-center text-[8px]
                             font-bold
                             bg-indigo-500 text-white"
                  style={{
                    marginLeft: i > 0 ? '-6px' : 0,
                    borderColor: isDark ? '#0a0a0a' : '#fff',
                    borderWidth: '1.5px',
                    borderStyle: 'solid',
                  }}
                >
                  {a.avatar
                    ? <img src={a.avatar}
                           className="w-full h-full
                                      object-cover" />
                    : a.name?.charAt(0).toUpperCase()
                  }
                </div>
              ))
            : (
              <div className={`size-5 rounded-full border
                border-dashed flex items-center
                justify-center
                ${isDark
                  ? 'border-[rgba(255,255,255,0.12)]'
                  : 'border-slate-300'
                }`} />
            )
          }
        </div>
      </div>
    </div>
  )
}

function BoardColumn({
  column, tasks, isDark, width,
  onAddTask, onTaskClick, onDeleteColumn, onDeleteTask,
  showConfirm, setConfirmModal
}) {
  const { setNodeRef, isOver } = useDroppable({
    id: column._id,
  })
  const colColor = getColumnColor(column.name)
  const [showMenu, setShowMenu] = useState(false)

  return (
    <div className="flex flex-col shrink-0 rounded-xl
             overflow-hidden"
      style={{
        width: width || '280px',
        minWidth: '200px',
        maxWidth: '380px',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        flexShrink: 0,
      }}>
      {/* Column header */}
      <div className={`px-3 py-2.5 flex items-center
        gap-2
        ${isDark
          ? 'bg-[rgba(255,255,255,0.04)]'
          : 'bg-slate-200/60'
        }`}>
        <div
          className="size-2.5 rounded-full shrink-0"
          style={{ backgroundColor: colColor }}
        />
        <span className={`text-[10px] font-semibold
          uppercase tracking-widest
          ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>
          {column.name}
        </span>
        <div className={`size-[18px] rounded flex items-center
          justify-center text-[10px] font-bold
          ${isDark
            ? 'bg-[rgba(255,255,255,0.08)] text-slate-400'
            : 'bg-slate-300/60 text-slate-600'
          }`}>
          {tasks.length}
        </div>
        <div className="flex-1" />
        <div className="relative">
          <button
            onClick={() => setShowMenu(p => !p)}
            className={`p-0.5 rounded transition-colors
              ${isDark
                ? 'text-slate-600 hover:text-slate-300 hover:bg-[rgba(255,255,255,0.06)]'
                : 'text-slate-400 hover:text-slate-600 hover:bg-slate-300/40'
              }`}
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              more_horiz
            </span>
          </button>
          {showMenu && (
            <div className={`absolute right-0 top-7 w-40
              rounded-xl shadow-xl z-20 overflow-hidden
              ${isDark
                ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
                : 'bg-white border border-slate-200'
              }`}>
              {!column.isDefault && (
                <button
                  onClick={() => {
                    setShowMenu(false)
                    onDeleteColumn(column._id)
                  }}
                  className="w-full flex items-center gap-2
                             px-3 py-2 text-sm text-red-500
                             hover:bg-red-500/10 transition-colors"
                >
                  <span className="material-symbols-outlined
                                   text-[16px]">
                    delete
                  </span>
                  Delete column
                </button>
              )}
              {column.isDefault && (
                <div className="px-3 py-2 text-xs
                                text-slate-500">
                  Default columns cannot be deleted
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Column body */}
      <SortableContext
        items={tasks.map(t => t._id)}
        strategy={verticalListSortingStrategy}
      >
        <div
          ref={setNodeRef}
          className={`flex-1 overflow-y-auto px-2
          py-1.5 space-y-2 min-h-[80px]
          custom-scrollbar
          ${isDark
            ? 'bg-[rgba(255,255,255,0.02)]'
            : 'bg-slate-100/80'
          }`}
          style={{
            flex: 1,
            overflowY: 'auto',
            minHeight: 0,
            backgroundColor: isOver
              ? isDark
                ? 'rgba(99,102,241,0.05)'
                : 'rgba(99,102,241,0.04)'
              : undefined,
            transition: 'background-color 150ms ease',
          }}
        >
          {tasks.length === 0 && (
            <div className={`flex flex-col items-center
              justify-center h-32 border border-dashed
              rounded-xl gap-2 text-xs
              ${isDark
                ? 'border-[rgba(255,255,255,0.08)] text-slate-700'
                : 'border-slate-300 text-slate-400'
              }`}>
              <span className="material-symbols-outlined
                               text-[28px] opacity-40">
                inbox
              </span>
              <span>No tasks yet</span>
            </div>
          )}
          {tasks.map(task => (
            <TaskCard
              key={task._id}
              task={task}
              isDark={isDark}
              onClick={onTaskClick}
              onDelete={onDeleteTask}
            />
          ))}
        </div>
      </SortableContext>

      {/* Column footer */}
      <div className={`px-2 pb-2
        ${isDark
          ? 'bg-[rgba(255,255,255,0.02)]'
          : 'bg-slate-100/80'
        }`}>
        <button
          onClick={() => onAddTask(column._id)}
          className={`w-full h-8 rounded-lg text-xs
            flex items-center justify-center gap-1
            border border-dashed transition-colors
            ${isDark
              ? 'border-[rgba(255,255,255,0.08)] text-slate-600 hover:bg-[rgba(255,255,255,0.04)] hover:text-slate-400'
              : 'border-slate-300 text-slate-400 hover:bg-slate-200/60 hover:text-slate-600'
            }`}
        >
          <span className="material-symbols-outlined
                           text-[16px]">
            add
          </span>
          Add task
        </button>
      </div>
    </div>
  )
}

function TaskDetailPanel({
  task, columns, members, isDark,
  onClose, onUpdate, onDelete, showConfirm
}) {
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
  const { user } = useSelector(s => s.auth)
  const [editTitle, setEditTitle] = useState(task.title)
  const [editDesc, setEditDesc] = useState(task.description || '')
  const [editingDesc, setEditingDesc] = useState(false)
  const [comments, setComments] = useState([])
  const [newComment, setNewComment] = useState('')
  const [posting, setPosting] = useState(false)
  const [saving, setSaving] = useState(false)
  const [showPriorityMenu, setShowPriorityMenu] = useState(false)
  const [showStatusMenu, setShowStatusMenu] = useState(false)
  const [showAssignMenu, setShowAssignMenu] = useState(false)

  const currentColumn = columns.find(c => c._id === task.column)

  // Fetch comments on mount
  useEffect(() => {
    const fetchComments = async () => {
      try {
        const res = await api.get(`/tasks/${task._id}/comments`)
        setComments(res.data?.data?.comments || [])
      } catch (err) {
        console.error('Comments fetch error:', err)
      }
    }
    fetchComments()
  }, [task._id])

  // Save title on blur
  const handleTitleBlur = async () => {
    if (editTitle.trim() === task.title) return
    if (!editTitle.trim()) {
      setEditTitle(task.title)
      return
    }
    try {
      const res = await api.patch(`/tasks/${task._id}`, {
        title: editTitle.trim()
      })
      onUpdate(res.data?.data?.task)
    } catch (err) {
      console.error('Update title error:', err)
    }
  }

  // Save description on blur
  const handleDescBlur = async () => {
    if (editDesc === (task.description || '')) return
    try {
      const res = await api.patch(`/tasks/${task._id}`, {
        description: editDesc
      })
      onUpdate(res.data?.data?.task)
    } catch (err) {
      console.error('Update desc error:', err)
    }
  }

  // Change priority
  const handlePriorityChange = async (priority) => {
    setShowPriorityMenu(false)
    try {
      const res = await api.patch(`/tasks/${task._id}`,
        { priority })
      onUpdate(res.data?.data?.task)
    } catch (err) {
      console.error('Priority update error:', err)
    }
  }

  // Change status (move to column)
  const handleStatusChange = async (columnId) => {
    setShowStatusMenu(false)
    try {
      const res = await api.patch(
        `/tasks/${task._id}/move`,
        { newColumnId: columnId, newOrder: 0 }
      )
      onUpdate(res.data?.data?.task)
    } catch (err) {
      console.error('Status change error:', err)
    }
  }

  // Assign member
  const handleAssign = async (memberId) => {
    setShowAssignMenu(false)
    const isAssigned = task.assignees?.some(
      a => (a._id || a) === memberId
    )
    try {
      if (isAssigned) {
        const res = await api.delete(
          `/tasks/${task._id}/assign/${memberId}`
        )
        onUpdate(res.data?.data?.task)
      } else {
        const res = await api.post(
          `/tasks/${task._id}/assign`,
          { assigneeId: memberId }
        )
        onUpdate(res.data?.data?.task)
      }
    } catch (err) {
      console.error('Assign error:', err)
    }
  }

  // Post comment
  const handlePostComment = async () => {
    if (!newComment.trim()) return
    try {
      setPosting(true)
      const res = await api.post(
        `/tasks/${task._id}/comments`,
        { content: newComment.trim() }
      )
      const comment = res.data?.data?.comment
      if (comment) setComments(prev => [...prev, comment])
      setNewComment('')
    } catch (err) {
      console.error('Comment post error:', err)
    } finally {
      setPosting(false)
    }
  }

  const priority = PRIORITY_CONFIG[task.priority] ||
                   PRIORITY_CONFIG.medium

  return (
    <div
      className={`fixed right-0 top-0 h-full w-[480px]
        flex flex-col z-50
        shadow-[-12px_0_40px_rgba(0,0,0,0.3)]
        transition-transform duration-300
        md:w-[480px] w-full
        ${isDark
          ? 'bg-[#141414] border-l border-[rgba(255,255,255,0.07)]'
          : 'bg-white border-l border-slate-200'
        }`}
      style={{
        top: '0',
        zIndex: 40,
      }}
    >
      {/* Panel header */}
      <div className={`h-12 flex items-center
        justify-between px-4 border-b shrink-0
        ${isDark
          ? 'border-[rgba(255,255,255,0.06)]'
          : 'border-slate-200'
        }`}>
        <div className="flex items-center gap-1.5
                        text-[10px] font-medium
                        uppercase tracking-wider
                        text-slate-500">
          <span>Board</span>
          <span className="material-symbols-outlined
                           text-[12px]">
            chevron_right
          </span>
          <span>{currentColumn?.name || 'Column'}</span>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={() => setShowDeleteConfirm(true)}
            className={`p-1.5 rounded-md transition-colors
              text-red-400 hover:bg-red-500/10
              cursor-pointer`}
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              delete
            </span>
          </button>
          <button
            onClick={onClose}
            className={`p-1.5 rounded-md transition-colors
              ${isDark
                ? 'text-slate-500 hover:text-slate-200 hover:bg-[rgba(255,255,255,0.06)]'
                : 'text-slate-400 hover:text-slate-700 hover:bg-slate-100'
              }`}
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              close
            </span>
          </button>
        </div>
      </div>

      {/* Panel body */}
      <div className="flex-1 overflow-y-auto
                      custom-scrollbar p-6">
        {/* Priority + Title */}
        <div className="flex items-start gap-2 mb-6">
          <span
            className="material-symbols-outlined
                       text-[20px] mt-1 shrink-0"
            style={{ color: priority.color }}
          >
            {priority.icon}
          </span>
          <textarea
            value={editTitle}
            onChange={e => setEditTitle(e.target.value)}
            onBlur={handleTitleBlur}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                e.preventDefault()
                e.target.blur()
              }
            }}
            rows={2}
            className={`flex-1 bg-transparent border-none
              p-0 text-xl font-semibold resize-none
              focus:outline-none focus:ring-0 leading-tight
              ${isDark ? 'text-white' : 'text-slate-900'}`}
          />
        </div>

        {/* Properties */}
        <div className={`rounded-xl p-4 mb-6 space-y-1
          ${isDark
            ? 'bg-[rgba(255,255,255,0.03)]'
            : 'bg-slate-50'
          }`}>

          {/* Assignees */}
          <div className="flex items-center h-9 relative">
            <span className={`w-28 text-xs font-medium
              ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
              Assignees
            </span>
            <button
              onClick={() => setShowAssignMenu(p => !p)}
              className={`flex items-center gap-1.5 px-2
                py-1 rounded-lg text-sm transition-colors
                ${isDark
                  ? 'hover:bg-[rgba(255,255,255,0.06)] text-white'
                  : 'hover:bg-slate-100 text-slate-700'
                }`}
            >
              {task.assignees?.length > 0
                ? task.assignees.map((a, i) => (
                    <span key={i}
                      className="size-6 rounded-full
                                 bg-indigo-500 text-white
                                 text-[10px] font-bold
                                 flex items-center
                                 justify-center">
                      {a.name?.charAt(0) || '?'}
                    </span>
                  ))
                : <span className="text-xs text-slate-500">
                    Add assignee
                  </span>
              }
            </button>
            {showAssignMenu && (
              <div className={`absolute left-28 top-9
                w-52 rounded-xl shadow-xl z-30
                overflow-hidden
                ${isDark
                  ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
                  : 'bg-white border border-slate-200'
                }`}>
                {members.map(m => {
                  const memberId = m.user?._id || m._id
                  const name = m.user?.name || m.name
                  const isAssigned = task.assignees?.some(
                    a => (a._id || a) === memberId
                  )
                  return (
                    <button
                      key={memberId}
                      onClick={() => handleAssign(memberId)}
                      className={`w-full flex items-center
                        gap-2 px-3 py-2 text-sm
                        transition-colors text-left
                        ${isDark
                          ? 'hover:bg-white/5 text-slate-300'
                          : 'hover:bg-slate-50 text-slate-700'
                        }`}
                    >
                      <span className="size-6 rounded-full
                                       bg-indigo-500 text-white
                                       text-[10px] font-bold
                                       flex items-center
                                       justify-center shrink-0">
                        {name?.charAt(0) || '?'}
                      </span>
                      <span className="flex-1 truncate">
                        {name}
                      </span>
                      {isAssigned && (
                        <span className="material-symbols-outlined
                                         text-[14px] text-indigo-500">
                          check
                        </span>
                      )}
                    </button>
                  )
                })}
              </div>
            )}
          </div>

          {/* Priority */}
          <div className="flex items-center h-9 relative">
            <span className={`w-28 text-xs font-medium
              text-slate-500`}>
              Priority
            </span>
            <button
              onClick={() => setShowPriorityMenu(p => !p)}
              className={`flex items-center gap-1.5 px-2
                py-1 rounded-lg text-sm transition-colors
                ${isDark
                  ? 'hover:bg-[rgba(255,255,255,0.06)]'
                  : 'hover:bg-slate-100'
                }`}
              style={{ color: priority.color }}
            >
              <span className="material-symbols-outlined
                               text-[16px]">
                {priority.icon}
              </span>
              <span className="font-medium">
                {priority.label}
              </span>
            </button>
            {showPriorityMenu && (
              <div className={`absolute left-28 top-9
                w-44 rounded-xl shadow-xl z-30
                overflow-hidden
                ${isDark
                  ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
                  : 'bg-white border border-slate-200'
                }`}>
                {Object.entries(PRIORITY_CONFIG).map(
                  ([key, cfg]) => (
                    <button
                      key={key}
                      onClick={() => handlePriorityChange(key)}
                      className={`w-full flex items-center
                        gap-2 px-3 py-2 text-sm
                        transition-colors
                        ${isDark
                          ? 'hover:bg-white/5'
                          : 'hover:bg-slate-50'
                        }`}
                      style={{ color: cfg.color }}
                    >
                      <span className="material-symbols-outlined
                                       text-[16px]">
                        {cfg.icon}
                      </span>
                      {cfg.label}
                    </button>
                  )
                )}
              </div>
            )}
          </div>

          {/* Status */}
          <div className="flex items-center h-9 relative">
            <span className={`w-28 text-xs font-medium
              text-slate-500`}>
              Status
            </span>
            <button
              onClick={() => setShowStatusMenu(p => !p)}
              className={`flex items-center gap-1.5 px-2
                py-1 rounded-lg text-sm transition-colors
                ${isDark
                  ? 'hover:bg-[rgba(255,255,255,0.06)] text-white'
                  : 'hover:bg-slate-100 text-slate-700'
                }`}
            >
              <div
                className="size-2 rounded-full"
                style={{
                  backgroundColor: getColumnColor(
                    currentColumn?.name || ''
                  )
                }}
              />
              {currentColumn?.name || 'Unknown'}
            </button>
            {showStatusMenu && (
              <div className={`absolute left-28 top-9
                w-48 rounded-xl shadow-xl z-30
                overflow-hidden
                ${isDark
                  ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
                  : 'bg-white border border-slate-200'
                }`}>
                {columns.map(col => (
                  <button
                    key={col._id}
                    onClick={() => handleStatusChange(col._id)}
                    className={`w-full flex items-center
                      gap-2 px-3 py-2 text-sm
                      transition-colors
                      ${isDark
                        ? 'hover:bg-white/5 text-slate-300'
                        : 'hover:bg-slate-50 text-slate-700'
                      }`}
                  >
                    <div
                      className="size-2 rounded-full"
                      style={{
                        backgroundColor:
                          getColumnColor(col.name)
                      }}
                    />
                    {col.name}
                    {col._id === task.column && (
                      <span className="material-symbols-outlined
                                       text-[14px] text-indigo-500
                                       ml-auto">
                        check
                      </span>
                    )}
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Due date */}
          <div className="flex items-center h-9">
            <span className={`w-28 text-xs font-medium
              text-slate-500`}>
              Due date
            </span>
            <input
              type="date"
              defaultValue={task.dueDate
                ? new Date(task.dueDate)
                    .toISOString().split('T')[0]
                : ''}
              onChange={async (e) => {
                try {
                  const res = await api.patch(
                    `/tasks/${task._id}`,
                    { dueDate: e.target.value || null }
                  )
                  onUpdate(res.data?.data?.task)
                } catch (err) {
                  console.error('Due date error:', err)
                }
              }}
              className={`text-sm px-2 py-1 rounded-lg
                border-none outline-none
                ${isDark
                  ? 'bg-transparent text-slate-300 [color-scheme:dark]'
                  : 'bg-transparent text-slate-700'
                }`}
            />
          </div>
        </div>

        {/* Description */}
        {/* Description */}
        <div className="mb-6">
          <div className="flex items-center justify-between mb-2">
            <p className={`text-xs font-semibold uppercase
              tracking-widest
              ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
              Description
            </p>
            {!editingDesc && (
              <button
                onClick={() => setEditingDesc(true)}
                className={`p-1 rounded transition-colors
                  cursor-pointer
                  ${isDark
                    ? 'text-slate-600 hover:text-slate-300 hover:bg-[rgba(255,255,255,0.06)]'
                    : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100'
                  }`}>
                <span className="material-symbols-outlined
                                 text-[16px]">edit</span>
              </button>
            )}
            {editingDesc && (
              <button
                onClick={() => {
                  handleDescBlur()
                  setEditingDesc(false)
                }}
                className="px-2 py-0.5 rounded-md text-xs
                  font-semibold bg-indigo-600 text-white
                  cursor-pointer">
                Save
              </button>
            )}
          </div>
          {editingDesc ? (
            <textarea
              autoFocus
              value={editDesc}
              onChange={e => setEditDesc(e.target.value)}
              onBlur={() => {
                handleDescBlur()
                setEditingDesc(false)
              }}
              rows={4}
              className={`w-full bg-transparent border-none
                p-0 text-sm resize-none focus:outline-none
                focus:ring-0 leading-relaxed
                ${isDark
                  ? 'text-slate-400 placeholder-slate-700'
                  : 'text-slate-600 placeholder-slate-400'
                }`}
              placeholder="Add a description..."
            />
          ) : (
            <p
              onClick={() => setEditingDesc(true)}
              className={`text-sm leading-relaxed
                cursor-text min-h-[60px]
                ${editDesc
                  ? isDark ? 'text-slate-400' : 'text-slate-600'
                  : isDark ? 'text-slate-700' : 'text-slate-400'
                }`}>
              {editDesc || 'Click to add a description...'}
            </p>
          )}
        </div>

        {/* Activity + Comments */}
        <div className={`border-t pt-6
          ${isDark
            ? 'border-[rgba(255,255,255,0.06)]'
            : 'border-slate-100'
          }`}>
          <p className={`text-xs font-semibold uppercase
            tracking-widest mb-4
            ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
            Activity
          </p>

          {/* Task activity log */}
          {task.activity?.length > 0 && (
            <div className="space-y-3 mb-4">
              {task.activity.slice(-5).map((act, i) => (
                <div key={i}
                     className="flex gap-2 items-start">
                  <div className={`size-5 rounded-full
                    flex items-center justify-center
                    shrink-0
                    ${isDark
                      ? 'bg-[rgba(255,255,255,0.06)]'
                      : 'bg-slate-100'
                    }`}>
                    <span className="material-symbols-outlined
                                     text-[11px] text-slate-500">
                      edit
                    </span>
                  </div>
                  <div className="flex-1">
                    <p className={`text-xs leading-relaxed
                      ${isDark
                        ? 'text-slate-500'
                        : 'text-slate-500'
                      }`}>
                      {act.action}
                    </p>
                    <span className="text-[10px] text-slate-600">
                      {timeAgo(act.createdAt || new Date())}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Comments list */}
          <div className="space-y-4 mb-4">
            {comments.length === 0 ? (
              <p className={`text-xs italic
                ${isDark ? 'text-slate-700' : 'text-slate-400'}`}>
                No comments yet. Be the first to comment.
              </p>
            ) : (
              comments.map(comment => (
                <div key={comment._id}
                     className="flex gap-3 items-start">
                  <div className="size-7 rounded-full
                    bg-indigo-500 text-white
                    text-[10px] font-bold
                    flex items-center justify-center
                    shrink-0 overflow-hidden">
                    {comment.author?.avatar
                      ? <img src={comment.author.avatar}
                             className="w-full h-full
                                        object-cover" />
                      : comment.author?.name?.charAt(0)
                          ?.toUpperCase() || '?'
                    }
                  </div>
                  <div className={`flex-1 rounded-xl p-3
                    ${isDark
                      ? 'bg-[rgba(255,255,255,0.04)]'
                      : 'bg-slate-50'
                    }`}>
                    <div className="flex items-center
                                    justify-between mb-1">
                      <span className={`text-xs font-semibold
                        ${isDark
                          ? 'text-slate-200'
                          : 'text-slate-800'
                        }`}>
                        {comment.author?.name || 'Unknown'}
                      </span>
                      <span className="text-[10px]
                                       text-slate-500">
                        {timeAgo(comment.createdAt)}
                      </span>
                    </div>
                    <p className={`text-sm leading-relaxed
                      ${isDark
                        ? 'text-slate-400'
                        : 'text-slate-600'
                      }`}>
                      {comment.content}
                    </p>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* Comment input */}
      <div className={`p-4 border-t shrink-0
        ${isDark
          ? 'border-[rgba(255,255,255,0.06)] bg-[#141414]'
          : 'border-slate-100 bg-white'
        }`}>
        <div className={`flex items-center gap-2
          rounded-xl px-3 py-2 border
          ${isDark
            ? 'bg-[rgba(255,255,255,0.04)] border-[rgba(255,255,255,0.07)]'
            : 'bg-slate-50 border-slate-200'
          }`}>
          <div className="size-6 rounded-full bg-indigo-500
                          text-white text-[10px] font-bold
                          flex items-center justify-center
                          shrink-0">
            {user?.name?.charAt(0) || '?'}
          </div>
          <input
            type="text"
            placeholder="Add a comment..."
            value={newComment}
            onChange={e => setNewComment(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && !e.shiftKey)
                handlePostComment()
            }}
            className={`flex-1 bg-transparent border-none
              outline-none text-sm
              ${isDark
                ? 'text-white placeholder-slate-700'
                : 'text-slate-900 placeholder-slate-400'
              }`}
          />
          <button
            onClick={handlePostComment}
            disabled={!newComment.trim() || posting}
            className="text-indigo-500 disabled:opacity-30
                       transition-opacity"
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              send
            </span>
          </button>
        </div>
      </div>

      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-black/60
          backdrop-blur-sm z-[200]
          flex items-center justify-center px-4">
          <div className={`w-full max-sm rounded-2xl
            shadow-2xl p-6
            ${isDark
              ? 'bg-[#1a1a1a] border border-[rgba(255,255,255,0.08)]'
              : 'bg-white border border-slate-200'
            }`}>
            <div className="size-12 rounded-full
              bg-red-500/10 flex items-center
              justify-center mb-4">
              <span className="material-symbols-outlined
                               text-[24px] text-red-500">
                delete
              </span>
            </div>
            <h3 className={`text-base font-semibold mb-2
              ${isDark ? 'text-white' : 'text-slate-900'}`}>
              Delete Task
            </h3>
            <p className={`text-sm mb-6
              ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
              <span className="font-semibold">
                {task.title}
              </span>
              {' '}will be permanently deleted.
            </p>
            <div className="flex gap-3">
              <button
                onClick={() => setShowDeleteConfirm(false)}
                className={`flex-1 py-2.5 rounded-xl
                  text-sm font-semibold border cursor-pointer
                  transition-colors
                  ${isDark
                    ? 'border-[rgba(255,255,255,0.08)] text-slate-400 hover:bg-[rgba(255,255,255,0.06)]'
                    : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                  }`}>
                Cancel
              </button>
              <button
                onClick={() => {
                  setShowDeleteConfirm(false)
                  onClose()
                  onDelete(task._id)
                }}
                className="flex-1 py-2.5 rounded-xl
                  text-sm font-semibold text-white
                  bg-red-600 hover:bg-red-700
                  cursor-pointer transition-colors">
                Delete Task
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

function CreateTaskModal({
  isDark, defaultColumnId, columns,
  members, boardId, projectId, orgId,
  onClose, onCreated,
}) {
  const [form, setForm] = useState({
    title: '',
    description: '',
    priority: 'medium',
    dueDate: '',
    labels: '',
    columnId: defaultColumnId,
  })
  const [error, setError] = useState('')
  const [creating, setCreating] = useState(false)
  const [assignees, setAssignees] = useState([])
  const [showAssignPicker, setShowAssignPicker] = useState(false)
  const [showColDrop, setShowColDrop] = useState(false)
  const [showPriorityDrop, setShowPriorityDrop] =
    useState(false)
  const modalRef = useRef(null)

  useEffect(() => {
    const handler = (e) => {
      if (!e.target.closest('[data-dropdown]')) {
        setShowColDrop(false)
        setShowPriorityDrop(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () =>
      document.removeEventListener('mousedown', handler)
  }, [])

  const handleCreate = async () => {
    if (!form.title.trim()) {
      setError('Task title is required')
      return
    }
    if (!form.columnId) {
      setError('Please select a column')
      return
    }
    try {
      setCreating(true)
      setError('')

      // CORRECT route: POST /api/boards/:boardId/columns/:columnId/tasks
      const res = await api.post(
        `/boards/${boardId}/columns/${form.columnId}/tasks`,
        {
          title: form.title.trim(),
          description: form.description.trim(),
          priority: form.priority,
          dueDate: form.dueDate || undefined,
          labels: form.labels.trim().length > 0
            ? form.labels.split(',').map(s=>s.trim()).filter(Boolean) : undefined,
          assignees: assignees.length > 0 ? assignees : undefined
        }
      )

      const newTask = res.data?.data?.task
      if (newTask) {
        onCreated(newTask, form.columnId)
      } else {
        onCreated(null, form.columnId)
      }
      onClose()
    } catch (err) {
      console.error('Create task error:', err)
      setError(
        err.response?.data?.message ||
        'Failed to create task'
      )
    } finally {
      setCreating(false)
    }
  }

  return (
    <div className="fixed inset-0 bg-black/60
                    backdrop-blur-sm z-[60] flex
                    items-center justify-center p-4">
      <div className={`w-full max-w-lg rounded-2xl
        shadow-2xl overflow-hidden animate-in
        fade-in zoom-in-95 duration-200
        ${isDark
          ? 'bg-[#141414] border border-[rgba(255,255,255,0.1)]'
          : 'bg-white border border-slate-200'
        }`}>
        <div className={`px-6 py-4 border-b flex
          items-center justify-between
          ${isDark
            ? 'border-[rgba(255,255,255,0.06)]'
            : 'border-slate-100'
          }`}>
          <h2 className={`text-lg font-bold
            ${isDark ? 'text-white' : 'text-slate-900'}`}>
            New Task
          </h2>
          <button
            onClick={onClose}
            className={`p-1 rounded-md transition-colors
              ${isDark
                ? 'text-slate-500 hover:text-slate-200 hover:bg-white/5'
                : 'text-slate-400 hover:text-slate-700 hover:bg-slate-100'
              }`}
          >
            <span className="material-symbols-outlined
                             text-[20px]">
              close
            </span>
          </button>
        </div>

        <div className="p-6 space-y-4">
          {error && (
            <div className={`p-3 rounded-lg text-sm mb-4
              ${isDark ? 'bg-red-500/10 text-red-400 border border-red-500/20' 
                       : 'bg-red-50 text-red-600 border border-red-100'}`}>
              {error}
            </div>
          )}

          <div>
            <label className={`block text-xs font-bold
              uppercase tracking-wider mb-1.5
              ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
              Task Title
            </label>
            <input
              autoFocus
              required
              type="text"
              placeholder="What needs to be done?"
              value={form.title}
              onChange={e => setForm({...form, title: e.target.value})}
              className={`w-full px-3 py-2.5 rounded-xl
                border text-sm transition-all focus:ring-2
                focus:ring-indigo-500/20 outline-none
                ${isDark
                  ? 'bg-[rgba(255,255,255,0.03)] border-[rgba(255,255,255,0.08)] text-white placeholder-slate-700 focus:border-indigo-500/50'
                  : 'bg-slate-50 border-slate-200 text-slate-900 placeholder-slate-400 focus:border-indigo-500'
                }`}
            />
          </div>

  <div>
    <label className={`block text-xs font-bold
      uppercase tracking-wider mb-1.5
      ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
      Column
    </label>
    <div data-dropdown className="relative">
      <button
        type="button"
        onClick={() => {
          setShowColDrop(p => !p)
          setShowPriorityDrop(false)
        }}
        className={`w-full flex items-center
          justify-between px-3 py-2 rounded-xl
          text-sm border text-left cursor-pointer
          ${isDark
            ? 'bg-[rgba(255,255,255,0.06)] border-[rgba(255,255,255,0.08)] text-white'
            : 'bg-slate-50 border-slate-200 text-slate-900'
          }`}>
        <span>
          {columns.find(c => c._id === form.columnId)
            ?.name || 'Select column'}
        </span>
        <span className="material-symbols-outlined
                         text-[18px] text-slate-400">
          expand_more
        </span>
      </button>
      {showColDrop && (
        <div className={`absolute top-full left-0
          right-0 mt-1 rounded-xl z-20 overflow-hidden
          shadow-xl border
          ${isDark
            ? 'bg-[#1a1a1a] border-[rgba(255,255,255,0.08)]'
            : 'bg-white border-slate-200'
          }`}>
          {columns.map(col => (
            <button
              key={col._id}
              type="button"
              onClick={() => {
                setForm(f => ({ ...f, columnId: col._id }))
                setShowColDrop(false)
              }}
              className={`w-full flex items-center
                gap-2 px-3 py-2.5 text-sm text-left
                transition-colors cursor-pointer
                ${form.columnId === col._id
                  ? isDark
                    ? 'bg-indigo-500/10 text-indigo-400'
                    : 'bg-indigo-50 text-indigo-600'
                  : isDark
                    ? 'text-slate-300 hover:bg-white/5'
                    : 'text-slate-700 hover:bg-slate-50'
                }`}>
              <div className="size-2 rounded-full"
                style={{
                  backgroundColor:
                    col.name === 'Done' ? '#10b981' :
                    col.name === 'In Progress' ? '#6366f1' :
                    col.name === 'Review' ? '#f59e0b' :
                    '#94a3b8'
                }} />
              {col.name}
              {form.columnId === col._id && (
                <span className="material-symbols-outlined
                  text-[14px] text-indigo-500 ml-auto">
                  check
                </span>
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  </div>

          <div>
            <label className={`block text-xs font-bold
              uppercase tracking-wider mb-1.5
              ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
              Description
              <span className="ml-2 lowercase font-normal opacity-70">(Optional)</span>
            </label>
            <textarea
              placeholder="Add more details..."
              value={form.description}
              onChange={e => setForm({...form, description: e.target.value})}
              rows={3}
              className={`w-full px-3 py-2 rounded-xl
                border text-sm transition-all focus:ring-2
                focus:ring-indigo-500/20 outline-none
                resize-none
                ${isDark
                  ? 'bg-[rgba(255,255,255,0.03)] border-[rgba(255,255,255,0.08)] text-white placeholder-slate-700 focus:border-indigo-500/50'
                  : 'bg-slate-50 border-slate-200 text-slate-900 placeholder-slate-400 focus:border-indigo-500'
                }`}
            />
