          </div>
        )}
      </div>

      <div className={`p-4 border-t text-xs
        ${isDark
          ? 'border-[rgba(255,255,255,0.06)] text-slate-600'
          : 'border-slate-100 text-slate-400'
        }`}>
        Project members appear in task assignee dropdowns.
      </div>
    </div>
  )
