export default function BoardPage() {
  const { orgId, projectId } = useParams()
  const { isDark } = useTheme()
  const navigate = useNavigate()
  const [board, setBoard] = useState(null)
  const [project, setProject] = useState(null)
  const [columns, setColumns] = useState([])
  const [tasksByColumn, setTasksByColumn] = useState({})
  const [members, setMembers] = useState([])
  const [orgMembers, setOrgMembers] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [activeTask, setActiveTask] = useState(null)
  const [selectedTask, setSelectedTask] = useState(null)
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showMembersPanel, setShowMembersPanel] = useState(false)
  const [targetColumnId, setTargetColumnId] = useState(null)
  const [searchQuery, setSearchQuery] = useState('')
  const [toast, setToast] = useState(null)

  const showToast = useCallback((message, type = 'error') => {
    setToast({ message, type })
  }, [])
  const socketRef = useRef()
  const deletingRef = useRef(new Set())

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 5,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  )

  const [confirmModal, setConfirmModal] = useState(null)

  const showConfirm = useCallback(({
    title, message, confirmText,
    confirmColor, onConfirm
  }) => {
    setConfirmModal({
      title, message, confirmText,
      confirmColor, onConfirm
    })
  }, [])

  const colWidth = React.useMemo(() => {
    const count = columns.length
    if (count === 0) return '280px'
    const available = window.innerWidth - 240 - (count + 1) * 12 - 32
    const w = Math.floor(available / count)
    return `${Math.max(220, Math.min(w, 340))}px`
  }, [columns.length])

  const totalTasks = React.useMemo(() => {
    return Object.values(tasksByColumn).flat().length
  }, [tasksByColumn])

  const getFilteredTasks = useCallback((colId) => {
    const tasks = tasksByColumn[colId] || []
    if (!searchQuery) return tasks
    return tasks.filter(t => {
      const q = searchQuery.toLowerCase().trim()
      return t.title?.toLowerCase().includes(q) ||
             t.description?.toLowerCase().includes(q) ||
             t.labels?.some(l => l.toLowerCase().includes(q))
    })
  }, [tasksByColumn, searchQuery])

  const fetchBoard = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)

      // CORRECT: /api/organizations/:orgId/projects/:id
      const projectRes = await api.get(
        `/organizations/${orgId}/projects/${projectId}`
      )

      const projectData =
        projectRes.data?.data?.project ||
        projectRes.data?.data ||
        projectRes.data

      const boardData = projectData?.board
      const cols = boardData?.columns || []

      setProject(projectData)
      setBoard(boardData)
      setColumns(cols)

      if (!boardData?._id) {
        setLoading(false)
        return
      }

      // CORRECT: /api/tasks?boardId=:boardId
      const tasksRes = await api.get(
        `/tasks?boardId=${boardData._id}`
      )
      const allTasks = tasksRes.data?.data?.tasks || []

      // Group by column
      const grouped = {}
      cols.forEach(col => { grouped[col._id] = [] })
      allTasks.forEach(task => {
        const colId = task.column?._id || task.column
        if (grouped[colId]) {
          grouped[colId].push(task)
        }
      })
      Object.keys(grouped).forEach(colId => {
        grouped[colId].sort((a, b) => a.order - b.order)
      })
      setTasksByColumn(grouped)

      // Fetch PROJECT members for task assignment
      // These are users added to this specific project
      const projMembersRes = await api.get(
        `/organizations/${orgId}/projects/${projectId}/members`
      ).catch(() => null)

      if (projMembersRes) {
        const projMembers =
          projMembersRes.data?.data?.members || []
        setMembers(projMembers)
      }

      // Fetch ALL org members for "Add to project" panel
      const orgMembersRes = await api.get(
        `/organizations/${orgId}/members`
      )
      setOrgMembers(orgMembersRes.data?.data?.members || [])

    } catch (err) {
      console.error('Board fetch error:', err)
      setError(
        err.response?.data?.message ||
        err.message ||
        'Failed to load board'
      )
    } finally {
      setLoading(false)
    }
  }, [orgId, projectId])

  useEffect(() => {
    setLoading(true)
    setColumns([])
    setTasksByColumn({})
    if (orgId && projectId) {
      fetchBoard()
    }
  }, [orgId, projectId])

  // Socket.io integration
  useEffect(() => {
    if (!board?._id) return

    const socketUrl = import.meta.env.VITE_SOCKET_URL ||
                     'http://localhost:5000'
    const socket = io(socketUrl, { withCredentials: true })
    socketRef.current = socket

    socket.emit('join:board', { boardId: board._id })

    socket.on('task:moved', (data) => {
      fetchBoard()
    })

    socket.on('task:created', ({ task }) => {
      setTasks(prev => {
        if (prev.some(t => t.title === task.title)) return prev
        return [...prev, task]
      })
    })

    socket.on('task:updated', ({ task }) => {
      const colId = task.column?._id || task.column
      setTasksByColumn(prev => ({
        ...prev,
        [colId]: (prev[colId] || []).map(t => t._id === task._id ? task : t)
      }))
      if (selectedTask?._id === task._id) setSelectedTask(task)
    })

    socket.on('task:deleted', ({ taskId }) => {
      setTasksByColumn(prev => {
        const next = { ...prev }
        Object.keys(next).forEach(cid => {
          next[cid] = next[cid].filter(t => t._id !== taskId)
        })
        return next
      })
      if (selectedTask?._id === taskId) setSelectedTask(null)
    })

    return () => {
      socket.emit('leave:board', { boardId: board._id })
      socket.disconnect()
    }
  }, [board?._id, selectedTask?._id])

  // DnD Handlers
  const handleDragStart = (event) => {
    const { active } = event
    const task = Object.values(tasksByColumn).flat().find(t => t._id === active.id)
    setActiveTask(task)
  }

  const handleDragOver = useCallback((event) => {
    const { active, over } = event
    if (!over || !active) return
    if (active.id === over.id) return

    const activeId = String(active.id)
    const overId = String(over.id)

    // Find source column of active task
    let sourceColId = null
    for (const [colId, tasks] of
         Object.entries(tasksByColumn)) {
      if (tasks.some(t => String(t._id) === activeId)) {
        sourceColId = colId
        break
      }
    }
    if (!sourceColId) return

    // Determine target column
    // over.id could be a column id or a task id
    let targetColId = null

    // Check if over is a column directly
    if (columns.some(c => String(c._id) === overId)) {
      targetColId = overId
    } else {
      // over is a task ΓÇö find its column
      for (const [colId, tasks] of
           Object.entries(tasksByColumn)) {
        if (tasks.some(t => String(t._id) === overId)) {
          targetColId = colId
          break
        }
      }
    }

    if (!targetColId || sourceColId === targetColId) return

    setTasksByColumn(prev => {
      const next = { ...prev }
      const sourceTask = next[sourceColId]
        ?.find(t => String(t._id) === activeId)
      if (!sourceTask) return prev

      next[sourceColId] = next[sourceColId]
        .filter(t => String(t._id) !== activeId)
      next[targetColId] = [
        ...(next[targetColId] || []),
        { ...sourceTask, column: targetColId }
      ]
      return next
    })
  }, [tasksByColumn, columns])

  const handleAddColumn = async () => {
    const newColumnName = window.prompt('Enter column name:')
    if (!newColumnName) return
    try {
      // CORRECT: POST /api/boards/:boardId/columns
      const res = await api.post(
        `/boards/${board._id}/columns`,
        { name: newColumnName.trim() }
      )
      const newCol = res.data?.data?.column
      if (newCol) {
        setColumns(prev => [...prev, newCol])
        setTasksByColumn(prev => ({
          ...prev,
          [newCol._id]: []
        }))
      }
    } catch (err) {
      console.error('Column create error:', err)
    }
  }

  const handleDeleteColumn = async (columnId) => {
    showConfirm({
      title: 'Delete Column',
      message: 'Delete this column and all its tasks? Cannot be undone.',
      confirmText: 'Delete Column',
      confirmColor: 'bg-red-600 hover:bg-red-700',
      onConfirm: async () => {
        setConfirmModal(null)
        try {
          await api.delete(`/columns/${columnId}`)
          setColumns(prev => prev.filter(c => c._id !== columnId))
          setTasksByColumn(prev => {
            const next = { ...prev }
            delete next[columnId]
            return next
          })
        } catch (err) {
          console.error('Col delete error:', err)
        }
      }
    })
  }

  const handleDragEnd = useCallback(async (event) => {
    const { active, over } = event
    setActiveTask(null)

    if (!over || !active) return

    const activeId = String(active.id)
    const overId = String(over.id)

    // Find current column and index
    let currentColId = null
    let currentIdx = 0

    for (const [colId, tasks] of
         Object.entries(tasksByColumn)) {
      const idx = tasks.findIndex(
        t => String(t._id) === activeId
      )
      if (idx !== -1) {
        currentColId = colId
        currentIdx = idx
        break
      }
    }

    if (!currentColId) return

    const colTasks = tasksByColumn[currentColId] || []

    // Reorder within same column if over is a task
    const isOverTask = colTasks.some(
      t => String(t._id) === overId
    )

    if (isOverTask && activeId !== overId) {
      const oldIdx = colTasks.findIndex(
        t => String(t._id) === activeId
      )
      const newIdx = colTasks.findIndex(
        t => String(t._id) === overId
      )
      if (oldIdx !== -1 && newIdx !== -1 &&
          oldIdx !== newIdx) {
        const reordered = arrayMove(
          colTasks, oldIdx, newIdx
        )
        setTasksByColumn(prev => ({
          ...prev,
          [currentColId]: reordered
        }))
        currentIdx = newIdx
      }
    }

    try {
      await api.patch(`/tasks/${activeId}/move`, {
        newColumnId: currentColId,
        newOrder: currentIdx,
      })
    } catch (err) {
      console.error('Move task error:', err)
      fetchBoard()
    }
  }, [tasksByColumn, fetchBoard])

  const handleTaskCreated = useCallback((newTask, columnId) => {
    if (!newTask) return
    setTasksByColumn(prev => {
      const colTasks = prev[columnId] || []
      if (colTasks.some(t => t._id === newTask._id)) return prev
      return {
        ...prev,
        [columnId]: [...colTasks, newTask]
      }
    })
  }, [])

  const handleUpdateTask = (updatedTask) => {
    const colId = updatedTask.column?._id || updatedTask.column
    setTasksByColumn(prev => ({
      ...prev,
      [colId]: (prev[colId] || []).map(t => t._id === updatedTask._id ? updatedTask : t)
    }))
    setSelectedTask(updatedTask)
  }

  const handleDeleteTask = useCallback(async (taskId) => {
    if (deletingRef.current.has(taskId)) return
    deletingRef.current.add(taskId)

    // Close modal immediately before API call
    setConfirmModal(null)

    try {
      await api.delete(`/tasks/${taskId}`)

      // Update state after successful delete
      setTasksByColumn(prev => {
        const next = { ...prev }
        Object.keys(next).forEach(colId => {
          next[colId] = next[colId].filter(
            t => t._id !== taskId
          )
        })
        return next
      })
      setSelectedTask(prev =>
        prev?._id === taskId ? null : prev
      )
      showToast('Task deleted.', 'success')
    } catch (err) {
      console.error('Delete task error:', err)
      showToast(
        err.response?.data?.message ||
        'Failed to delete task',
        'error'
      )
      // Refetch to restore correct state
      fetchBoard()
    } finally {
      deletingRef.current.delete(taskId)
    }
  }, [showToast, fetchBoard])

  const filteredTasksCount = Object.values(tasksByColumn).flat().filter(t =>
    t.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    t.labels?.some(l => l.toLowerCase().includes(searchQuery.toLowerCase()))
  ).length

  if (loading) return (
    <div className="flex-1 flex items-center justify-center">
      <div className="size-8 border-2 border-indigo-500
                      border-t-transparent rounded-full animate-spin" />
    </div>
  )

  return (
    <div
      className={`flex flex-col overflow-hidden
        ${isDark ? 'bg-[#0a0a0a]' : 'bg-[#f4f5f7]'}`}
      style={{ height: 'calc(100vh - 64px)' }}
    >

      {showMembersPanel && (
        <>
          <div
            className="fixed inset-0 bg-black/20 z-40"
            onClick={() => setShowMembersPanel(false)}
          />
          <ProjectMembersPanel
            isDark={isDark}
            projectId={projectId}
            orgId={orgId}
            projectMembers={members}
            orgMembers={orgMembers}
            onClose={() => setShowMembersPanel(false)}
            onMembersUpdated={() => {
              fetchBoard()
              setShowMembersPanel(false)
            }}
            showConfirmInPanel={showConfirm}
            showToastInPanel={showToast}
          />
        </>
      )}

      {/* Board Header */}
      <div className={`px-6 py-4 flex flex-wrap items-center
        justify-between gap-4 border-b shrink-0
        ${isDark
          ? 'bg-[#0f0f0f] border-[rgba(255,255,255,0.06)]'
          : 'bg-white border-slate-200'
        }`}>
        <div className="flex items-center gap-4">
          <button
            onClick={() => navigate('/projects')}
            className={`p-1.5 rounded-lg transition-colors
              ${isDark
                ? 'text-slate-500 hover:text-slate-200 hover:bg-white/5'
                : 'text-slate-400 hover:text-slate-700 hover:bg-slate-100'
              }`}
          >
            <span className="material-symbols-outlined
                             text-[20px]">
              arrow_back
            </span>
          </button>
          <div>
            <h1 className={`text-lg font-bold
              ${isDark ? 'text-white' : 'text-slate-900'}`}>
              {board?.name || 'Project Board'}
            </h1>
            <p className="text-xs text-slate-500 font-medium">
              {members.length} members ΓÇó {totalTasks} tasks
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => setShowMembersPanel(p => !p)}
            className={`flex items-center gap-1.5 px-3
              py-1.5 rounded-lg text-xs font-medium
              transition-colors
              ${isDark
                ? 'border border-[rgba(255,255,255,0.08)] text-slate-400 hover:bg-[rgba(255,255,255,0.06)]'
                : 'border border-slate-200 text-slate-600 hover:bg-slate-50'
              }`}
          >
            <span className="material-symbols-outlined text-[16px]">
              group
            </span>
            Members
          </button>
          <div className="relative">
            <span className="material-symbols-outlined
                             absolute left-3 top-1/2 -translate-y-1/2
                             text-[16px] text-slate-500">
              search
            </span>
            <input
              type="text"
              placeholder="Search tasks..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className={`pl-9 pr-4 py-1.5 rounded-lg border-none
                text-sm w-48 transition-all focus:w-64
                ${isDark
                  ? 'bg-[rgba(255,255,255,0.05)] text-white focus:bg-[rgba(255,255,255,0.08)]'
                  : 'bg-slate-100 text-slate-900 focus:bg-slate-200/50'
                }`}
            />
          </div>
          <button
            onClick={() => {
              setTargetColumnId(columns[0]?._id)
              setShowCreateModal(true)
            }}
            className="flex items-center gap-1.5 px-4 py-1.5
                       bg-indigo-600 hover:bg-indigo-700
                       text-white text-sm font-semibold
                       rounded-lg shadow-lg shadow-indigo-600/20
                       transition-all active:scale-95"
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              add
            </span>
            New Task
          </button>
        </div>
      </div>

      {/* Board Layout */}
      <DndContext
        sensors={sensors}
        collisionDetection={pointerWithin}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragEnd={handleDragEnd}
      >
        <div className={`flex-1 overflow-x-auto overflow-y-hidden
          ${isDark ? 'bg-[#0a0a0a]' : 'bg-[#f4f5f7]'}`}
          style={{ height: 'calc(100vh - 64px - 64px - 60px)' }}>
          <div className="flex gap-3 h-full px-4 py-3"
               style={{ minWidth: 'max-content', alignItems: 'stretch' }}>
            {columns.map(column => (
              <BoardColumn
                key={column._id}
                column={column}
                tasks={getFilteredTasks(column._id)}
                isDark={isDark}
                width={colWidth}
                onTaskClick={setSelectedTask}
                onAddTask={(cid) => {
                  setTargetColumnId(cid)
                  setShowCreateModal(true)
                }}
                onDeleteColumn={handleDeleteColumn}
                onDeleteTask={handleDeleteTask}
                showConfirm={showConfirm}
                setConfirmModal={setConfirmModal}
              />
            ))}

            {/* Add Column Button */}
            <div className="shrink-0" style={{ width: '280px' }}>
              <button
                onClick={handleAddColumn}
                className={`w-full h-12 rounded-xl border border-dashed
                  flex items-center justify-center gap-2 transition-all
                  ${isDark
                    ? 'border-[rgba(255,255,255,0.08)] text-slate-500 hover:bg-white/5 hover:border-slate-700'
                    : 'border-slate-200 text-slate-400 hover:bg-slate-50 hover:border-slate-300'
                  }`}
              >
                <span className="material-symbols-outlined text-[20px]">add</span>
                <span className="text-sm font-semibold">Add Column</span>
              </button>
            </div>
          </div>
        </div>

        <DragOverlay>
          {activeTask ? (
            <div className="w-[280px] rotate-3 cursor-grabbing">
              <TaskCard
                task={activeTask}
                isDark={isDark}
                onClick={() => {}}
                isDragging
              />
            </div>
          ) : null}
        </DragOverlay>
      </DndContext>

      {/* Modals & Panels */}
      {selectedTask && (
        <>
          <div
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40"
            onClick={() => setSelectedTask(null)}
          />
          <TaskDetailPanel
            task={selectedTask}
            columns={columns}
            members={members}
            isDark={isDark}
            onClose={() => setSelectedTask(null)}
            onUpdate={handleUpdateTask}
            onDelete={handleDeleteTask}
            showConfirm={showConfirm}
          />
        </>
      )}

      {showCreateModal && board && (
        <CreateTaskModal
          isDark={isDark}
          defaultColumnId={targetColumnId || columns[0]?._id}
          columns={columns}
          members={members}
          boardId={board._id}
          projectId={projectId}
          orgId={orgId}
          onClose={() => {
            setShowCreateModal(false)
            setTargetColumnId(null)
          }}
          onCreated={handleTaskCreated}
        />
      )}

      {confirmModal && (
        <ConfirmModal
          isDark={isDark}
          title={confirmModal.title}
          message={confirmModal.message}
          confirmText={confirmModal.confirmText}
          confirmColor={confirmModal.confirmColor}
          onConfirm={confirmModal.onConfirm}
          onCancel={() => setConfirmModal(null)}
        />
      )}

      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  )
}
